def gen(rng, size):
    n = max(1, min(size, 1000))
    ops = []
    for _ in range(n):
        choice = rng.random()
        if choice < 0.3:
            ops.append('../')
        elif choice < 0.5:
            ops.append('./')
        else:
            name = ''.join(rng.choice('abc123') for _ in range(rng.randint(1, 5)))
            ops.append(name + '/')
    return [ops]

